#!/bin/bash
# SubagentStart hook: Records agent start for metrics.
# Generated by buddyx-forge.

INPUT=$(cat)
if ! command -v jq &>/dev/null; then
  exit 0
fi
AGENT_TYPE=$(echo "$INPUT" | jq -r '.agent_type // empty' 2>/dev/null)
AGENT_TYPE=$(echo "$AGENT_TYPE" | tr -cd 'a-zA-Z0-9-')
PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"
DASHBOARD_DIR="${PROJECT_DIR}/.claude/dashboard"

if ! echo "$AGENT_TYPE" | grep -q "^myapp-"; then
  exit 0
fi

mkdir -p "$DASHBOARD_DIR" 2>/dev/null

# Save git state snapshot
git -C "$PROJECT_DIR" diff --name-only > "/tmp/myapp-eval-pre-files-${AGENT_TYPE}" 2>/dev/null

# Record start time
echo "$(date +%s)" > "/tmp/myapp-start-time-${AGENT_TYPE}"

# Update live status
TIMESTAMP=$(date -Iseconds)
cat > "${DASHBOARD_DIR}/live-status.json" <<EOF
{
  "current_agent": "${AGENT_TYPE}",
  "status": "RUNNING",
  "started_at": "${TIMESTAMP}",
  "last_updated": "${TIMESTAMP}"
}
EOF

echo "{\"time\":\"${TIMESTAMP}\",\"agent\":\"${AGENT_TYPE}\",\"event\":\"START\"}" >> "${DASHBOARD_DIR}/events.jsonl"

exit 0
